'    WHEN PRICE BETWEEN 200 AND 500 THEN ''200-500''',
'    ELSE ''Above 500''',
'  END AS PRICE_RANGE,',
'  COUNT(*) AS COUNT_BOOKS',
'FROM BOOKS',
'GROUP BY ',
