,p_plug_display_point=>'SUB_REGIONS'
,p_query_type=>'SQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'SELECT ',
'       A.AUTHOR_ID,',
'       A.AUTHOR_NAME,',
'       A.COUNTRY,',
'       A.DOB,',
'       A.BIO,',
'       A.STATUS,',
'       COUNT(B.BOOK_ID) AS TOTAL_BOOKS,',
'       ''Manage Author'' View_Books,',
'       ''+'' Edit,',
'       ''#'' Selector',
'    ',
'  FROM AUTHORS A',
'  LEFT JOIN BOOKS B',
'    ON A.AUTHOR_ID = B.AUTHOR_ID',
' WHERE (:P4_AUTHOR_NAME IS NULL OR UPPER(A.AUTHOR_NAME) LIKE ''%'' || UPPER(:P4_AUTHOR_NAME) || ''%'')',
'  -- AND (:P4_STATUS IS NULL OR A.STATUS = :P4_STATUS)',
' GROUP BY ',
'          A.AUTHOR_ID,',
'          A.AUTHOR_NAME,',
'          A.COUNTRY,',
'          A.DOB,',
'          A.BIO,',
'          A.STATUS',
'',
''))
