wwv_flow_imp_page.create_page_da_action(
 p_id=>wwv_flow_imp.id(152110389901600919538)
,p_event_id=>wwv_flow_imp.id(152110389832657919537)
,p_event_result=>'TRUE'
,p_action_sequence=>10
,p_execute_on_page_init=>'N'
,p_action=>'NATIVE_JAVASCRIPT_CODE'
,p_attribute_01=>wwv_flow_string.join(wwv_flow_t_varchar2(
'var i, i_ids = "", i_id,',
'',
'model = this.data.model;',
'',
'for ( i = 0; i < this.data.selectedRecords.length; i++ ) {',
'    ',
'    i_id = model.getValue( this.data.selectedRecords[i], "AUTHOR_ID");',
'    ',
'    i_ids += model.getValue( this.data.selectedRecords[i], "AUTHOR_ID") + ":";',
'    ',
'}',
'',
'apex.item( "P4_ARRAY_SELECTION" ).setValue (i_ids);'))
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(152110390200367919541)
,p_process_sequence=>10
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Delete_Selected'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'DECLARE',
'    v_deleted_books   NUMBER := 0;',
'    v_deleted_authors NUMBER := 0;',
'BEGIN',
'    FOR r IN (',
'        SELECT TO_NUMBER(column_value) AS author_id',
'        FROM TABLE(apex_string.split(RTRIM(:P4_ARRAY_SELECTION, '':''), '':''))',
'    ) LOOP',
'',
'        -- Delete child records first',
'        DELETE FROM books',
'        WHERE author_id = r.author_id;',
'',
'        v_deleted_books := v_deleted_books + SQL%ROWCOUNT;',
'',
'        -- Delete parent record',
'        DELETE FROM authors',
'        WHERE author_id = r.author_id;',
'',
'        IF SQL%ROWCOUNT = 0 THEN',
'            RAISE_APPLICATION_ERROR(',
'                -20002,',
'                ''No matching author found for AUTHOR_ID = '' || r.author_id',
'            );',
'        END IF;',
'',
'        v_deleted_authors := v_deleted_authors + SQL%ROWCOUNT;',
'',
'    END LOOP;',
'',
'    -- Optional: show success message in APEX UI',
'    apex_application.g_print_success_message :=',
'        ''Deleted Authors: '' || v_deleted_authors || '', Deleted Books: '' || v_deleted_books;',
'',
'EXCEPTION',
'    WHEN OTHERS THEN',
'        -- Rollback any partial changes',
'        ROLLBACK;',
'        RAISE_APPLICATION_ERROR(',
'            -20001,',
'            ''Error deleting records: '' || SQLERRM',
'        );',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(152110390151027919540)
,p_process_success_message=>'Selected records got deleted succesfully!!'
,p_internal_uid=>152110390200367919541
);
end;
